// Toggle.jsx - Composant générique avec render props
export function Toggle({ children, initialOn = false }) {
  const [on, setOn] = useState(initialOn);
  const toggle = () => setOn(prev => !prev);
  return children({ on, toggle });
}

// Exemple 1 : Interrupteur simple
function Interrupteur() {
  return (
    <Toggle>
      {({ on, toggle }) => (
        <button onClick={toggle} style={{ backgroundColor: on ? 'green' : 'gray' }}>
          {on ? 'ALLUMÉ' : 'ÉTEINT'}
        </button>
      )}
    </Toggle>
  );
}

// Exemple 2 : Panneau déroulant
function Panneau() {
  return (
    <Toggle>
      {({ on, toggle }) => (
        <div>
          <button onClick={toggle}>Afficher/Masquer</button>
          {on && <div className="panel">Contenu secret du panneau</div>}
        </div>
      )}
    </Toggle>
  );
}
```
**Intérêt du pattern** : Le composant `Toggle` ne connaît pas l'interface (bouton, panneau). Il ne fait que gérer la logique d'état et fournit les données à l'enfant. Cela permet une **réutilisabilité maximale** et suit le principe de séparation des préoccupations (logique vs présentation).

