function SearchInput({ onSearch }) {
  const [query, setQuery] = useState('');
  const [charCount, setCharCount] = useState(0);

  const handleChange = (e) => {
    const value = e.target.value;
    setQuery(value);
    setCharCount(value.length);
    // Validation à chaque frappe
    if (value.length >= 2) {
      onSearch(value);
    }
  };

  const handleSubmit = () => {
    if (query.trim()) onSearch(query);
  };

  return (
    <div>
      <input 
        type="text" 
        value={query} 
        onChange={handleChange}
        placeholder="Rechercher..."
      />
      <p>Caractères : {charCount}</p>
      <button onClick={handleSubmit} disabled={!query.trim()}>
        Chercher
      </button>
    </div>
  );
}
```
**Avantages de la version contrôlée :**
- Validation en temps réel (désactivation dynamique du bouton)
- Feedback instantané à l'utilisateur (compteur de caractères)
- Possibilité d'exécuter la recherche dès que la saisie atteint 2 caractères
- Le composant a une "source unique de vérité" (l'état `query`)
- Plus facile à tester car l'état est géré React, pas caché dans le DOM

