// Modal.jsx
import { createContext, useContext } from 'react';

const ModalContext = createContext();

function Modal({ isOpen, onClose, children }) {
  if (!isOpen) return null;
  return (
    <ModalContext.Provider value={{ onClose }}>
      <div className="modal-overlay" onClick={onClose}>
        <div className="modal-container" onClick={e => e.stopPropagation()}>
          {children}
        </div>
      </div>
    </ModalContext.Provider>
  );
}

function Header({ children }) {
  const { onClose } = useContext(ModalContext);
  return (
    <div className="modal-header">
      {children}
      <button className="close-btn" onClick={onClose}>×</button>
    </div>
  );
}

function Body({ children }) {
  return <div className="modal-body">{children}</div>;
}

function Footer({ children }) {
  return <div className="modal-footer">{children}</div>;
}

Modal.Header = Header;
Modal.Body = Body;
Modal.Footer = Footer;

export default Modal;

// Exemple d'utilisation
function MonApp() {
  const [showConfirm, setShowConfirm] = useState(false);
  const [showForm, setShowForm] = useState(false);

  return (
    <>
      <button onClick={() => setShowConfirm(true)}>Supprimer</button>
      <Modal isOpen={showConfirm} onClose={() => setShowConfirm(false)}>
        <Modal.Header>Confirmation</Modal.Header>
        <Modal.Body>Voulez-vous vraiment supprimer cet élément ?</Modal.Body>
        <Modal.Footer>
          <button onClick={() => setShowConfirm(false)}>Annuler</button>
          <button onClick={() => { /* suppression */ setShowConfirm(false); }}>
            Confirmer
          </button>
        </Modal.Footer>
      </Modal>
    </>
  );
}
```
Le pattern des sous-composants attachés permet une API expressive et intuitive, tout en maintenant la logique de la modal encapsulée.
